function calcAgeFromBirthdate(){const bd=document.getElementById('epBirthdate').value;const ageEl=document.getElementById('epAge');if(bd){const age=Math.floor((Date.now()-new Date(bd).getTime())/(365.25*24*3600*1000));ageEl.value=age>0&&age<120?age:'';}else{ageEl.value='';}}
async function changeCover(input){const f=input.files[0];if(!f)return;if(!f.type.startsWith('image/')){toast('Solo se permiten imágenes (JPG, PNG, WEBP)','err');input.value='';return;}
if(f.size>15*1024*1024){toast('La imagen es demasiado grande. Máximo 15MB','err');input.value='';return;}
toast('Subiendo portada...','inf');let url;try{url=await uploadImage(f,'covers');}catch(e){console.error('changeCover error:',e);toast('Error al subir la portada: '+(e.message||'Intentá de nuevo'),'err');input.value='';return;}
try{window.CU.cover=url;await updateDoc(doc(db,'users',window.CU.id),{cover:url});}catch(e){console.error('changeCover updateDoc error:',e);toast('Error al guardar la portada en tu perfil','err');input.value='';return;}
try{await addDoc(collection(db,'posts'),{userId:window.CU.id,userNick:window.CU.nick,userAv:window.CU.av||'',userXp:window.CU.xp||0,userVerified:window.CU.verified||false,text:`📸 ${window.CU.nick} actualizó su foto de portada.`,images:[url],profileAction:'cover',fish:'',weight:0,map:'',tech:'',video:'',link:null,time:serverTimestamp(),likes:0,comments:[],reactions:{},reactionCounts:{}});}catch(e){console.warn('cover post err',e);}
input.value='';renderProfile();toast('Portada actualizada ✅','ok');}
