function bannerFuego(cv,resize){const ctx=cv.getContext('2d');if(document.getElementById('profCover'))document.getElementById('profCover').style.background='linear-gradient(180deg,#0a0000,#2d0800,#4a1000)';const particles=Array.from({length:120},()=>mkFireParticle(cv));const embers=Array.from({length:40},()=>mkEmber(cv));function mkFireParticle(c){return{x:Math.random()*c.width,y:c.height+Math.random()*60,size:3+Math.random()*18,speed:0.8+Math.random()*2.5,wobble:Math.random()*Math.PI*2,wobbleSpeed:0.03+Math.random()*.05,alpha:0.6+Math.random()*.4,hue:10+Math.random()*30};}
function mkEmber(c){return{x:Math.random()*c.width,y:c.height+Math.random()*40,size:1+Math.random()*3,speed:1+Math.random()*3,vx:(Math.random()-.5)*1.5,alpha:Math.random()};}
function draw(){resize();ctx.clearRect(0,0,cv.width,cv.height);particles.forEach(p=>{p.y-=p.speed;p.wobble+=p.wobbleSpeed;p.x+=Math.sin(p.wobble)*1.2;p.size*=.995;p.alpha-=.003;if(p.y<-p.size||p.alpha<=0){Object.assign(p,mkFireParticle(cv));p.y=cv.height+10;}
const prog=1-(p.y/cv.height);const grd=ctx.createRadialGradient(p.x,p.y,0,p.x,p.y,p.size);grd.addColorStop(0,`hsla(${p.hue+prog*20},100%,70%,${p.alpha})`);grd.addColorStop(.5,`hsla(${p.hue},100%,50%,${p.alpha*.7})`);grd.addColorStop(1,`hsla(${p.hue-10},100%,30%,0)`);ctx.beginPath();ctx.fillStyle=grd;ctx.ellipse(p.x,p.y,p.size*.5,p.size,0,0,Math.PI*2);ctx.fill();});embers.forEach(e=>{e.y-=e.speed;e.x+=e.vx;e.alpha-=.008;if(e.y<-10||e.alpha<=0){Object.assign(e,mkEmber(cv));e.y=cv.height;}
ctx.beginPath();ctx.fillStyle=`rgba(255,${100+Math.random()*100},0,${e.alpha})`;ctx.arc(e.x,e.y,e.size,0,Math.PI*2);ctx.fill();});_bannerAnimFrame=requestAnimationFrame(draw);}
draw();}
function bannerFlores(cv,resize){const ctx=cv.getContext('2d');if(document.getElementById('profCover'))document.getElementById('profCover').style.background='linear-gradient(180deg,#0d0018,#1e0042,#2d0060)';const petals=Array.from({length:80},()=>mkPetal(cv));const particles=Array.from({length:40},()=>mkSparkle(cv));function mkPetal(c){return{x:Math.random()*c.width,y:c.height+Math.random()*100,size:6+Math.random()*16,speed:.4+Math.random()*1.4,vx:(Math.random()-.5)*1,rot:Math.random()*Math.PI*2,rotSpeed:.02+Math.random()*.04,alpha:.7+Math.random()*.3,hue:270+Math.random()*60};}
function mkSparkle(c){return{x:Math.random()*c.width,y:Math.random()*c.height,size:1+Math.random()*2,twinkle:Math.random()*Math.PI*2,speed:.02+Math.random()*.04};}
function drawPetal(x,y,size,rot,alpha,hue){ctx.save();ctx.translate(x,y);ctx.rotate(rot);ctx.globalAlpha=alpha;const g=ctx.createRadialGradient(0,0,0,0,0,size);g.addColorStop(0,`hsla(${hue},100%,80%,.9)`);g.addColorStop(.6,`hsla(${hue-20},90%,60%,.6)`);g.addColorStop(1,`hsla(${hue-30},80%,40%,0)`);ctx.fillStyle=g;ctx.beginPath();ctx.ellipse(0,-size*.5,size*.4,size*.9,0,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.ellipse(size*.4,0,size*.4,size*.9,Math.PI/3,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.ellipse(-size*.4,0,size*.4,size*.9,-Math.PI/3,0,Math.PI*2);ctx.fill();ctx.restore();}
function draw(){resize();ctx.clearRect(0,0,cv.width,cv.height);particles.forEach(s=>{s.twinkle+=s.speed;const a=.3+.6*((Math.sin(s.twinkle)+1)/2);ctx.beginPath();ctx.fillStyle=`rgba(200,160,255,${a})`;ctx.arc(s.x,s.y,s.size,0,Math.PI*2);ctx.fill();});petals.forEach(p=>{p.y-=p.speed;p.x+=p.vx+Math.sin(p.rot)*.5;p.rot+=p.rotSpeed;p.alpha-=.002;if(p.y<-p.size*2||p.alpha<=0){Object.assign(p,mkPetal(cv));p.y=cv.height+20;}
drawPetal(p.x,p.y,p.size,p.rot,p.alpha,p.hue);});_bannerAnimFrame=requestAnimationFrame(draw);}
draw();}
function bannerOcean(cv,resize){const ctx=cv.getContext('2d');if(document.getElementById('profCover'))document.getElementById('profCover').style.background='linear-gradient(180deg,#00050f,#001530,#002050)';const bubbles=Array.from({length:60},()=>mkBubble(cv));let t=0;function mkBubble(c){return{x:Math.random()*c.width,y:c.height+Math.random()*50,r:2+Math.random()*12,speed:.3+Math.random()*1,vx:(Math.random()-.5)*.8,alpha:.4+Math.random()*.5};}
function draw(){t+=.01;resize();ctx.clearRect(0,0,cv.width,cv.height);for(let w=0;w<3;w++){ctx.beginPath();ctx.moveTo(0,cv.height);for(let x=0;x<=cv.width;x+=10){const y=cv.height*.7+Math.sin(x*.02+t+w*2)*15+Math.sin(x*.04-t*.7+w)*8;ctx.lineTo(x,y);}
ctx.lineTo(cv.width,cv.height);ctx.closePath();ctx.fillStyle=`rgba(0,100,200,${.08+w*.04})`;ctx.fill();}
bubbles.forEach(b=>{b.y-=b.speed;b.x+=b.vx+Math.sin(t+b.r)*.3;b.alpha-=.0015;if(b.y<-b.r*2||b.alpha<=0){Object.assign(b,mkBubble(cv));b.y=cv.height;}
ctx.beginPath();ctx.strokeStyle=`rgba(100,200,255,${b.alpha})`;ctx.lineWidth=1.5;ctx.arc(b.x,b.y,b.r,0,Math.PI*2);ctx.stroke();ctx.fillStyle=`rgba(150,220,255,${b.alpha*.2})`;ctx.fill();});_bannerAnimFrame=requestAnimationFrame(draw);}
draw();}
function bannerAurora(cv,resize){const ctx=cv.getContext('2d');if(document.getElementById('profCover'))document.getElementById('profCover').style.background='linear-gradient(180deg,#000508,#001010,#001a15)';const stars=Array.from({length:80},()=>({x:Math.random()*800,y:Math.random()*300,r:Math.random()*1.5,t:Math.random()*Math.PI*2}));let t=0;function draw(){t+=.008;resize();stars.forEach(s=>{s.x=(s.x/800)*cv.width;s.y=(s.y/300)*cv.height;});ctx.clearRect(0,0,cv.width,cv.height);stars.forEach(s=>{s.t+=.02;const a=.3+.6*((Math.sin(s.t)+1)/2);ctx.beginPath();ctx.fillStyle=`rgba(200,255,240,${a})`;ctx.arc(s.x,s.y,s.r,0,Math.PI*2);ctx.fill();});const cols=['rgba(0,255,150','rgba(0,200,255','rgba(100,0,255','rgba(0,255,100'];for(let i=0;i<4;i++){ctx.save();ctx.globalAlpha=.15+Math.sin(t+i)*0.07;const grd=ctx.createLinearGradient(0,0,0,cv.height);grd.addColorStop(0,`${cols[i%cols.length]},0)`);grd.addColorStop(.3,`${cols[i%cols.length]},.6)`);grd.addColorStop(1,`${cols[(i+1)%cols.length]},0)`);ctx.fillStyle=grd;ctx.beginPath();const xBase=(i/4)*cv.width+Math.sin(t*.5+i)*60;const ww=cv.width*.35;ctx.moveTo(xBase,0);for(let y=0;y<=cv.height;y+=5){ctx.lineTo(xBase+Math.sin(y*.02+t+i)*40+ww*(y/cv.height),y);}
ctx.lineTo(xBase+ww,cv.height);ctx.lineTo(xBase,0);ctx.closePath();ctx.fill();ctx.restore();}
_bannerAnimFrame=requestAnimationFrame(draw);}
draw();}
function bannerGalaxy(cv,resize){const ctx=cv.getContext('2d');if(document.getElementById('profCover'))document.getElementById('profCover').style.background='linear-gradient(180deg,#000005,#050010,#0a0020)';const stars=Array.from({length:200},()=>({x:Math.random(),y:Math.random(),r:.5+Math.random()*2,t:Math.random()*Math.PI*2,speed:.01+Math.random()*.04,col:[`255,255,255`,`200,200,255`,`255,220,180`,`180,220,255`][Math.floor(Math.random()*4)]}));const nebula=Array.from({length:8},()=>({x:Math.random(),y:Math.random(),r:40+Math.random()*80,hue:200+Math.random()*160,t:Math.random()*Math.PI*2}));let t=0;function draw(){t+=.005;resize();ctx.clearRect(0,0,cv.width,cv.height);nebula.forEach(n=>{n.t+=.003;const g=ctx.createRadialGradient(n.x*cv.width,n.y*cv.height,0,n.x*cv.width,n.y*cv.height,n.r*(1+Math.sin(n.t)*.1));g.addColorStop(0,`hsla(${n.hue},100%,60%,.12)`);g.addColorStop(1,`hsla(${n.hue},80%,40%,0)`);ctx.fillStyle=g;ctx.beginPath();ctx.arc(n.x*cv.width,n.y*cv.height,n.r*1.5,0,Math.PI*2);ctx.fill();});stars.forEach(s=>{s.t+=s.speed;const a=.4+.6*((Math.sin(s.t)+1)/2);ctx.beginPath();ctx.fillStyle=`rgba(${s.col},${a})`;ctx.arc(s.x*cv.width,s.y*cv.height,s.r*(a*.5+.5),0,Math.PI*2);ctx.fill();});_bannerAnimFrame=requestAnimationFrame(draw);}
draw();}
function bannerStorm(cv,resize){const ctx=cv.getContext('2d');if(document.getElementById('profCover'))document.getElementById('profCover').style.background='linear-gradient(180deg,#050507,#0a0a10,#101018)';const drops=Array.from({length:120},()=>mkDrop(cv));let t=0,lightningT=0,lightningAlpha=0;function mkDrop(c){return{x:Math.random()*c.width,y:Math.random()*c.height,speed:4+Math.random()*8,len:8+Math.random()*20,alpha:.2+Math.random()*.5};}
function drawLightning(x,y,x2,y2,depth){if(depth<=0)return;const mx=(x+x2)/2+(Math.random()-.5)*60;const my=(y+y2)/2+(Math.random()-.5)*20;ctx.beginPath();ctx.moveTo(x,y);ctx.lineTo(mx,my);ctx.lineTo(x2,y2);ctx.strokeStyle=`rgba(200,220,255,${lightningAlpha})`;ctx.lineWidth=depth*.5;ctx.stroke();drawLightning(x,y,mx,my,depth-1);drawLightning(mx,my,x2,y2,depth-1);}
function draw(){t+=1;lightningT--;resize();ctx.clearRect(0,0,cv.width,cv.height);ctx.strokeStyle='rgba(150,180,255,.4)';ctx.lineWidth=1;drops.forEach(d=>{d.y+=d.speed;if(d.y>cv.height){Object.assign(d,mkDrop(cv));d.y=-d.len;}
ctx.beginPath();ctx.globalAlpha=d.alpha;ctx.moveTo(d.x,d.y);ctx.lineTo(d.x-2,d.y+d.len);ctx.stroke();});ctx.globalAlpha=1;if(lightningT<=0){lightningAlpha=.6+Math.random()*.4;lightningT=80+Math.random()*200;drawLightning(Math.random()*cv.width,0,Math.random()*cv.width,cv.height*.6,4);}
_bannerAnimFrame=requestAnimationFrame(draw);}
draw();}
