let _igRxnPopTimer=null;function igShowRxnPop(btn){clearTimeout(_igRxnPopTimer);const pop=document.getElementById('_igRxnPop');if(!pop)return;const r=btn.getBoundingClientRect();pop.style.left=r.left+'px';pop.style.top=(r.top-72)+'px';pop.style.display='flex';}
function igHideRxnPop(){_igRxnPopTimer=setTimeout(()=>{const pop=document.getElementById('_igRxnPop');if(pop&&!pop.matches(':hover'))pop.style.display='none';},300);}
let _igGifDebounce=null;function igToggleGifPicker(){const p=document.getElementById('_igGifPicker');if(!p)return;if(p.style.display==='flex'){p.style.display='none';return;}
const inp=document.getElementById('_igCmtInp');if(inp){const r=inp.getBoundingClientRect();p.style.bottom=(window.innerHeight-r.top+6)+'px';p.style.left=Math.max(8,r.left-40)+'px';p.style.transform='none';}
p.style.display='flex';p.style.flexDirection='column';igSearchGif('');setTimeout(()=>{const s=document.getElementById('_igGifSearch');if(s)s.focus();},50);}
async function igSearchGif(q){clearTimeout(_igGifDebounce);_igGifDebounce=setTimeout(async()=>{const grid=document.getElementById('_igGifGrid');if(!grid)return;grid.innerHTML='<div style="grid-column:1/-1;text-align:center;padding:16px;color:#65676b;font-size:.8rem;">⏳ Buscando...</div>';try{const query=q.trim()||'fishing';const url=`https://api.tenor.com/v2/search?q=${encodeURIComponent(query)}&key=AIzaSyAyimkuYQYF_FXVALexPmHA5a7li72Bkr0&limit=15&media_filter=gif`;const r=await fetch(url);const data=await r.json();const results=data.results||[];if(!results.length){grid.innerHTML='<div style="grid-column:1/-1;text-align:center;padding:16px;color:#65676b;font-size:.8rem;">Sin resultados</div>';return;}
window._igGifs=results.map(g=>g.media_formats?.gif?.url||g.media_formats?.tinygif?.url||'').filter(Boolean);grid.innerHTML=window._igGifs.map((url,i)=>`<img src="${url}" style="width:100%;aspect-ratio:1;object-fit:cover;cursor:pointer;border-radius:4px;transition:opacity .15s;"
          onclick="igSendGifComment(window._igGifs[${i}])"
          onmouseover="this.style.opacity='.8'" onmouseout="this.style.opacity='1'"
          loading="lazy">`).join('');}catch(e){const grid2=document.getElementById('_igGifGrid');if(grid2)grid2.innerHTML='<div style="grid-column:1/-1;text-align:center;padding:16px;color:#f55;font-size:.8rem;">Error cargando GIFs</div>';}},q?500:0);}
async function igSendGifComment(gifUrl){if(!_galPostId){toast('Sin post asociado','inf');return;}
if(!window.CU){toast('Iniciá sesión para comentar','err');return;}
document.getElementById('_igGifPicker').style.display='none';const isTrofeo=_galPostId.startsWith('trofeo_');const realId=isTrofeo?_galPostId.replace('trofeo_',''):_galPostId;const colName=isTrofeo?'trofeosPendientes':'posts';let p=(_posts||[]).find(p=>p.id===_galPostId);if(!p){try{const s=await getDoc(doc(db,colName,realId));if(s.exists()){p={id:_galPostId,...s.data()};(_posts||[]).push(p);}}catch(e){}}
if(!p){toast('No se pudo cargar el post','err');return;}
const nc=[...(p.comments||[]),{userId:window.CU.id,nick:window.CU.nick,av:window.CU.av||'',gender:window.CU.gender||'',gif:gifUrl,text:'',time:Date.now()}];p.comments=nc;await updateDoc(doc(db,colName,realId),{comments:nc});}
window.igShowRxnPop=igShowRxnPop;window.igHideRxnPop=igHideRxnPop;window.igToggleGifPicker=igToggleGifPicker;window.igSearchGif=igSearchGif;window.igSendGifComment=igSendGifComment;function igToggleStkPicker(){const p=document.getElementById('_igStkPick');if(!p)return;const gp=document.getElementById('_igGifPicker');if(gp)gp.style.display='none';const isOpen=p.classList.contains('open');if(isOpen){p.classList.remove('open');return;}
p.classList.add('open');const catsEl=document.getElementById('_igStkCats');if(catsEl&&!catsEl.children.length){catsEl.innerHTML='';STK_CATS.forEach(c=>{const btn=document.createElement('button');btn.className='stk-cat-btn';btn.style.background=c.color;btn.innerHTML='<span style="font-size:1.3rem;">'+c.emoji+'</span>'+c.label;btn.addEventListener('click',()=>igLoadStkCat(c.q,c.label));catsEl.appendChild(btn);});}
setTimeout(()=>{const s=document.getElementById('_igStkSearch');if(s)s.focus();},100);}
async function igLoadStkCat(query,label){const contentEl=document.getElementById('_igStkContent');if(!contentEl)return;contentEl.innerHTML='';const header=document.createElement('div');header.style.cssText='display:flex;align-items:center;padding:4px 8px;border-bottom:1px solid #dddfe2;';const back=document.createElement('button');back.className='stk-back';back.textContent='← Volver';back.addEventListener('click',()=>{contentEl.innerHTML='';});const title=document.createElement('span');title.style.cssText='font-size:.82rem;font-weight:700;color:#050505;flex:1;text-align:center;';title.textContent=label;header.appendChild(back);header.appendChild(title);contentEl.appendChild(header);const grid=document.createElement('div');grid.className='stk-grid';grid.innerHTML='<div style="grid-column:1/-1;text-align:center;padding:20px;color:#65676b;font-size:.82rem;">⏳ Cargando...</div>';contentEl.appendChild(grid);try{const res=await fetch('https://api.giphy.com/v1/stickers/search?api_key='+STK_API_KEY+'&limit=15&rating=g&q='+encodeURIComponent(query));const data=await res.json();_igRenderStickers(data.data,grid);}catch(e){grid.innerHTML='<div style="grid-column:1/-1;text-align:center;padding:12px;color:#65676b;">Error cargando</div>';}}
function _igRenderStickers(stickers,grid){if(!stickers||!stickers.length){grid.innerHTML='<div style="grid-column:1/-1;text-align:center;padding:16px;color:#65676b;">Sin resultados</div>';return;}
grid.innerHTML='';stickers.forEach(s=>{const url=(s.images?.fixed_height_small?.url)||(s.images?.original?.url)||'';const orig=(s.images?.original?.url)||url;const item=document.createElement('div');item.className='stk-item';const img=document.createElement('img');img.src=url;img.loading='lazy';img.alt='sticker';item.appendChild(img);item.addEventListener('click',()=>igSendSticker(orig));grid.appendChild(item);});}
let _igStkDebounce=null;function igSearchSticker(q){clearTimeout(_igStkDebounce);const contentEl=document.getElementById('_igStkContent');if(!q.trim()){if(contentEl)contentEl.innerHTML='';return;}
_igStkDebounce=setTimeout(async()=>{if(!contentEl)return;contentEl.innerHTML='';const header=document.createElement('div');header.style.cssText='display:flex;align-items:center;padding:4px 8px;border-bottom:1px solid #dddfe2;';const back=document.createElement('button');back.className='stk-back';back.textContent='← Volver';back.addEventListener('click',()=>{contentEl.innerHTML='';const s=document.getElementById('_igStkSearch');if(s)s.value='';});const title=document.createElement('span');title.style.cssText='font-size:.82rem;font-weight:700;color:#050505;flex:1;text-align:center;';title.textContent=q;header.appendChild(back);header.appendChild(title);contentEl.appendChild(header);const grid=document.createElement('div');grid.className='stk-grid';grid.innerHTML='<div style="grid-column:1/-1;text-align:center;padding:20px;color:#65676b;">🔍 Buscando...</div>';contentEl.appendChild(grid);try{const res=await fetch('https://api.giphy.com/v1/stickers/search?api_key='+STK_API_KEY+'&limit=15&rating=g&q='+encodeURIComponent(q));const data=await res.json();_igRenderStickers(data.data,grid);}catch(e){}},400);}
async function igSendSticker(gifUrl){if(!_galPostId){toast('Sin post asociado','inf');return;}
if(!window.CU){toast('Iniciá sesión','err');return;}
document.getElementById('_igStkPick')?.classList.remove('open');const isTrofeo=_galPostId.startsWith('trofeo_');const realId=isTrofeo?_galPostId.replace('trofeo_',''):_galPostId;const colName=isTrofeo?'trofeosPendientes':'posts';let p=(_posts||[]).find(p=>p.id===_galPostId);if(!p){try{const s=await getDoc(doc(db,colName,realId));if(s.exists()){p={id:_galPostId,...s.data()};(_posts||[]).push(p);}}catch(e){}}
if(!p){toast('No se pudo cargar el post','err');return;}
const nc=[...(p.comments||[]),{userId:window.CU.id,nick:window.CU.nick,av:window.CU.av||'',gender:window.CU.gender||'',gif:gifUrl,sticker:true,text:'',time:Date.now()}];p.comments=nc;await updateDoc(doc(db,colName,realId),{comments:nc});if(p.userId&&p.userId!==window.CU.id){sendNotifToUserWithPost(p.userId,`🎭 ${window.CU.nick} comentó con un sticker`,_galPostId);}}
window.igToggleStkPicker=igToggleStkPicker;window.igLoadStkCat=igLoadStkCat;window.igSearchSticker=igSearchSticker;window.igSendSticker=igSendSticker;window.igNav=igNav;window.igNavTo=igNavTo;window.igReact=igReact;window.igReactCmt=igReactCmt;window.igQuickRxnCmt=igQuickRxnCmt;window.igEditCmt=igEditCmt;window.igDelCmt=igDelCmt;window.igReplyCmt=igReplyCmt;window.igSubmitComment=igSubmitComment;window.igShare=igShare;window.igDownload=igDownload;window.igReport=igReport;window.openImgLightbox=openImgLightbox;window.openImgLightboxById=openImgLightboxById;function reportPost(pid,userNick){if(!window.CU){toast('Inicia sesión para reportar','err');return;}
document.getElementById('reportPostId').value=pid;document.getElementById('reportUser').value=userNick;document.getElementById('reportReason').value='';document.getElementById('reportDesc').value='';document.getElementById('reportErr').textContent='';om('mReport');}
async function submitReport(){const pid=document.getElementById('reportPostId').value;const reason=document.getElementById('reportReason').value;const desc=document.getElementById('reportDesc').value.trim();const reportedUser=document.getElementById('reportUser').value;if(!reason){document.getElementById('reportErr').textContent='Seleccioná un motivo';return;}
await addDoc(collection(db,'reports'),{postId:pid,reportedUser,reportedBy:window.CU.nick,reportedById:window.CU.id,reason,desc,time:serverTimestamp(),status:'pendiente'});cm('mReport');toast('Reporte enviado al administrador ✅','ok');}
function swAdminTab(el,tabId){document.querySelectorAll('.adm-tab').forEach(t=>t.classList.remove('adm-on'));el.classList.add('adm-on');['admt-reports','admt-posts','admt-users','admt-verif','admt-site','admt-parches','admt-torneos','admt-grupos','admt-ads','admt-live','admt-pezdelsemana','admt-xplevels','admt-insignias','admt-soporte','admt-faq'].forEach(id=>{const e=document.getElementById(id);if(e)e.style.display='none';});const tab=document.getElementById(tabId);if(tab)tab.style.display='block';if(tabId==='admt-parches')loadAdminPatches();if(tabId==='admt-torneos')loadAdminTorneos();if(tabId==='admt-grupos')loadAdminGrupos();if(tabId==='admt-users')loadAdminUsers();if(tabId==='admt-verif')loadVerifRequests();if(tabId==='admt-site')loadSiteConfig();if(tabId==='admt-ads')loadAdminAds();if(tabId==='admt-live')loadAdminLive();if(tabId==='admt-soporte')loadSoporteTickets();if(tabId==='admt-faq')loadAdminFaq();}